import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  X,
  Calendar,
  Search,
  Plus,
  CheckCircle,
  AlertCircle,
  Filter,
} from "lucide-react";
import "./Dashboard.css";
import "../../App.css";
import api from "../../api";

export default function CreatePage() {
  const navigate = useNavigate();

  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [crimeDate, setCrimeDate] = useState("");
  const [startDate, setStartDate] = useState("");
  const [priority, setPriority] = useState("High");
  const [status, setStatus] = useState("Open");
  const [leader, setLeader] = useState("");
  const [leaders, setLeaders] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [roleFilter, setRoleFilter] = useState("");
  const [regionFilter, setRegionFilter] = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [assignedMembers, setAssignedMembers] = useState([]);
  const [submitting, setSubmitting] = useState(false);
  const [msg, setMsg] = useState({ type: "", text: "" });
  const [roles, setRoles] = useState([]);
  const [regions, setRegions] = useState([]);

  const flash = (type, text) => {
    setMsg({ type, text });
    if (type === "success") {
      setTimeout(() => navigate("/cases"), 1500);
    } else {
      setTimeout(() => setMsg({ type: "", text: "" }), 4000);
    }
  };

  // Fetch lead investigators, roles, regions
  useEffect(() => {
    const fetchData = async () => {
      try {
        const [leadsRes, rolesRes, regionsRes] = await Promise.all([
          api.get("/users/leads"),
          api.get("/roles"),
          api.get("/regions"),
        ]);
        setLeaders(Array.isArray(leadsRes.data) ? leadsRes.data : []);
        setRoles(Array.isArray(rolesRes.data) ? rolesRes.data : []);
        setRegions(Array.isArray(regionsRes.data) ? regionsRes.data : []);
      } catch (err) {
        console.error("Error fetching data:", err);
      }
    };
    fetchData();
  }, []);

  // Search users with filters
  const handleSearch = async () => {
    try {
      const params = new URLSearchParams();
      if (searchTerm) params.append("q", searchTerm);
      if (roleFilter) params.append("role", roleFilter);
      if (regionFilter) params.append("region", regionFilter);
      const res = await api.get(`/users/search?${params.toString()}`);
      const existingIds = new Set(assignedMembers.map((m) => m._id));
      setSearchResults(
        (Array.isArray(res.data) ? res.data : []).filter(
          (u) => !existingIds.has(u._id),
        ),
      );
    } catch {
      setSearchResults([]);
    }
  };

  useEffect(() => {
    handleSearch();
  }, [searchTerm, roleFilter, regionFilter, assignedMembers]);

  const addMember = (member) => {
    if (!assignedMembers.find((m) => m._id === member._id)) {
      setAssignedMembers((prev) => [...prev, member]);
    }
    setSearchTerm("");
    setSearchResults([]);
  };

  const removeMember = (id) => {
    setAssignedMembers((prev) => prev.filter((m) => m._id !== id));
  };

  const handleCreateCase = async () => {
    // Validation
    if (!title.trim()) return flash("error", "Case title is required");
    if (!description.trim()) return flash("error", "Description is required");

    setSubmitting(true);
    try {
      const payload = {
        title: title.trim(),
        description: description.trim(),
        status,
        priority,
        start_date: startDate
          ? new Date(startDate).toISOString()
          : new Date().toISOString(),
        crime_date: crimeDate ? new Date(crimeDate).toISOString() : undefined,
        leader_id: leader || undefined,
        member_ids: assignedMembers.map((m) => m._id),
      };

      await api.post("/create-case", payload);
      flash("success", "Case created successfully! Redirecting to cases...");
    } catch (err) {
      flash("error", err.response?.data?.message || "Failed to create case");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="dashboardMain">
      {/* Header */}
      <header className="dashboardHeader">
        <div className="headerBranding">
          <h1 className="logoText">
            <span>LEGALLENS</span> Create Case
          </h1>
          <p className="systemStatus">
            Fill in the details to create a new investigation case
          </p>
        </div>
      </header>

      {/* Alert */}
      {msg.text && (
        <div
          className={`alertBanner ${msg.type === "success" ? "alertSuccess" : "alertError"}`}
          style={{
            display: "flex",
            alignItems: "center",
            gap: "0.5rem",
            marginBottom: "1.5rem",
          }}
        >
          {msg.type === "success" ? (
            <CheckCircle size={16} />
          ) : (
            <AlertCircle size={16} />
          )}
          {msg.text}
        </div>
      )}

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr 1fr",
          gap: "1.5rem",
        }}
      >
        {/* Case Details */}
        <div className="formSectionCard">
          <div className="sectionHeader">
            <div className="indicatorDot" />
            <h2>CASE DETAILS</h2>
          </div>
          <div style={{ padding: "1.5rem" }}>
            <div className="inputGroup">
              <label>Case Title *</label>
              <input
                type="text"
                placeholder="e.g. Downtown Bank Robbery Investigation"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
              />
            </div>
            <div className="inputGroup">
              <label>Description *</label>
              <textarea
                placeholder="Provide a detailed description of the case..."
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                rows={4}
                style={{ resize: "vertical" }}
              />
            </div>
            <div className="inputGroup">
              <label>Date of Crime</label>
              <input
                type="date"
                value={crimeDate}
                onChange={(e) => setCrimeDate(e.target.value)}
              />
            </div>
            <div className="inputGroup">
              <label>Case Start Date</label>
              <input
                type="date"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                max={new Date().toISOString().split("T")[0]}
              />
            </div>
          </div>
        </div>

        {/* Assigned To */}
        <div className="formSectionCard">
          <div className="sectionHeader">
            <div className="indicatorDot" style={{ background: "#34d399" }} />
            <h2>ASSIGNED TO</h2>
          </div>
          <div style={{ padding: "1.5rem" }}>
            {/* Filters */}
            <div className="assignedFiltersBar">
              <div className="assignedFiltersCopy">
                <p className="assignedFiltersTitle">Member filters</p>
                <p className="assignedFiltersHint">
                  Hover to filter by role or region
                </p>
              </div>

              <div className="assignedFilterTriggerWrap">
                <button
                  type="button"
                  className={`assignedFilterTrigger ${roleFilter || regionFilter ? "assignedFilterTriggerActive" : ""}`}
                  aria-label="Filter members"
                >
                  <Filter size={16} />
                  <span>Filter</span>
                  {(roleFilter || regionFilter) && (
                    <span className="assignedFilterCount">
                      {[roleFilter, regionFilter].filter(Boolean).length}
                    </span>
                  )}
                </button>

                <div className="assignedFilterMenu">
                  <div className="assignedFilterMenuHeader">
                    <span>Refine members</span>
                    {(roleFilter || regionFilter) && (
                      <button
                        type="button"
                        className="assignedFilterClear"
                        onClick={() => {
                          setRoleFilter("");
                          setRegionFilter("");
                        }}
                      >
                        Clear
                      </button>
                    )}
                  </div>

                  <div className="assignedFilterField">
                    <label htmlFor="member-role-filter">Role</label>
                    <select
                      id="member-role-filter"
                      value={roleFilter}
                      onChange={(e) => setRoleFilter(e.target.value)}
                    >
                      <option value="">All Roles</option>
                      {roles.map((r) => (
                        <option key={r._id} value={r.role_name}>
                          {r.role_name.replace(/_/g, " ")}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div className="assignedFilterField">
                    <label htmlFor="member-region-filter">Region</label>
                    <select
                      id="member-region-filter"
                      value={regionFilter}
                      onChange={(e) => setRegionFilter(e.target.value)}
                    >
                      <option value="">All Regions</option>
                      {regions.map((r) => (
                        <option key={r} value={r}>
                          {r}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>
            </div>

            {/* Search */}
            <div className="inputGroup">
              <label>Search Members</label>
              <div className="membersSearch">
                <Search size={16} color="#475569" />
                <input
                  type="text"
                  placeholder="Search by name..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  style={{
                    background: "transparent",
                    border: "none",
                    outline: "none",
                    color: "#fff",
                    fontSize: "0.875rem",
                    flex: 1,
                  }}
                />
                {searchTerm && (
                  <button
                    type="button"
                    onClick={() => setSearchTerm("")}
                    style={{
                      background: "none",
                      border: "none",
                      cursor: "pointer",
                      color: "#64748b",
                    }}
                  >
                    <X size={14} />
                  </button>
                )}
              </div>
            </div>

            {/* Members List */}
            <div
              style={{
                maxHeight: "200px",
                overflowY: "auto",
                marginTop: "1rem",
              }}
            >
              {searchResults.map((u) => (
                <div
                  key={u._id}
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    padding: "0.5rem",
                    borderBottom: "1px solid rgba(255,255,255,0.05)",
                  }}
                >
                  <div>
                    <p
                      style={{
                        margin: 0,
                        fontWeight: 600,
                        fontSize: "0.875rem",
                      }}
                    >
                      {u.name}
                    </p>
                    <p
                      style={{
                        margin: 0,
                        color: "#64748b",
                        fontSize: "0.75rem",
                      }}
                    >
                      {u.role_id?.role_name?.replace(/_/g, " ")} • {u.Region}
                    </p>
                  </div>
                  <button
                    type="button"
                    onClick={() => addMember(u)}
                    style={{
                      background: "rgba(79,70,229,0.2)",
                      border: "1px solid rgba(79,70,229,0.3)",
                      color: "#818cf8",
                      padding: "4px 12px",
                      borderRadius: 6,
                      cursor: "pointer",
                      fontSize: "0.8rem",
                      fontWeight: 600,
                    }}
                  >
                    <Plus
                      size={12}
                      style={{ display: "inline", marginRight: 4 }}
                    />
                    Add
                  </button>
                </div>
              ))}
              {searchResults.length === 0 && (
                <p style={{ color: "#334155", fontSize: "0.8rem" }}>
                  No members found.
                </p>
              )}
            </div>

            {/* Assigned Leader */}
            <div className="inputGroup" style={{ marginTop: "1rem" }}>
              <label>Assigned Leader</label>
              <select
                value={leader}
                onChange={(e) => setLeader(e.target.value)}
                style={{
                  background: "#1e293b",
                  border: "1px solid rgba(255,255,255,0.08)",
                  color: "#fff",
                  padding: "0.75rem 1rem",
                  borderRadius: 8,
                  fontSize: "0.9rem",
                  width: "100%",
                }}
              >
                <option value="">— Select Lead Investigator —</option>
                {leaders.map((l) => (
                  <option key={l._id} value={l._id}>
                    {l.name}
                  </option>
                ))}
              </select>
            </div>

            {/* Assigned Members */}
            {assignedMembers.length > 0 && (
              <div style={{ marginTop: "1rem" }}>
                <label>Assigned Members</label>
                <div
                  style={{
                    display: "flex",
                    flexWrap: "wrap",
                    gap: "0.5rem",
                    marginTop: "0.5rem",
                  }}
                >
                  {assignedMembers.map((m) => (
                    <div
                      key={m._id}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: "0.5rem",
                        background: "rgba(79,70,229,0.1)",
                        border: "1px solid rgba(79,70,229,0.25)",
                        borderRadius: 20,
                        padding: "4px 12px",
                        fontSize: "0.8rem",
                        color: "#818cf8",
                      }}
                    >
                      <div
                        style={{
                          width: 20,
                          height: 20,
                          borderRadius: "50%",
                          background: "rgba(79,70,229,0.3)",
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          fontWeight: 700,
                          fontSize: "0.65rem",
                        }}
                      >
                        {m.name?.charAt(0)?.toUpperCase()}
                      </div>
                      {m.name}
                      <button
                        type="button"
                        onClick={() => removeMember(m._id)}
                        style={{
                          background: "none",
                          border: "none",
                          cursor: "pointer",
                          color: "#818cf8",
                          display: "flex",
                          padding: 0,
                        }}
                      >
                        <X size={12} />
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Case Settings */}
        <div className="formSectionCard">
          <div className="sectionHeader">
            <div className="indicatorDot" style={{ background: "#f59e0b" }} />
            <h2>CASE SETTINGS</h2>
          </div>
          <div style={{ padding: "1.5rem" }}>
            <div className="inputGroup">
              <label>Priority</label>
              <select
                value={priority}
                onChange={(e) => setPriority(e.target.value)}
                style={{
                  background: "#1e293b",
                  border: "1px solid rgba(255,255,255,0.08)",
                  color: "#fff",
                  padding: "0.75rem 1rem",
                  borderRadius: 8,
                  fontSize: "0.9rem",
                  width: "100%",
                }}
              >
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
              </select>
            </div>
            <div className="inputGroup">
              <label>Status</label>
              <select
                value={status}
                onChange={(e) => setStatus(e.target.value)}
                style={{
                  background: "#1e293b",
                  border: "1px solid rgba(255,255,255,0.08)",
                  color: "#fff",
                  padding: "0.75rem 1rem",
                  borderRadius: 8,
                  fontSize: "0.9rem",
                  width: "100%",
                }}
              >
                <option value="Open">Open</option>
                <option value="Closed">Closed</option>
                <option value="Archived">Archived</option>
              </select>
            </div>
            <div
              style={{
                marginTop: "2rem",
                display: "flex",
                gap: "1rem",
                justifyContent: "flex-end",
              }}
            >
              <button
                type="button"
                className="btnCancel"
                onClick={() => navigate("/cases")}
                disabled={submitting}
              >
                Cancel
              </button>
              <button
                type="button"
                className="btnCreate"
                onClick={handleCreateCase}
                disabled={submitting}
              >
                {submitting ? (
                  "Creating..."
                ) : (
                  <>
                    <Plus size={16} style={{ marginRight: 6 }} />
                    Create Case
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
